async function createReport(context: any, scope: any[]) {
    context.log("Running Analysis - Creating Report");

    if (!scope || scope.length === 0) {
        return context.log("No data in scope");
    }

    const reportData = extractReportData(scope);
    const device_id = scope[0].device;

    if (!reportData.report_device) {
        reportData.report_device = device_id;
    }

    if (!reportData.report_device || !reportData.report_send_to || !reportData.report_start_date || !reportData.report_end_date || !reportData.report_variables?.length) {
        return context.log("Missing report fields. Required: report_device, report_variables, report_start_date, report_end_date, report_send_to");
    }

    const startDate = parseDate(reportData.report_start_date);
    const endDate = parseDate(reportData.report_end_date, true);

    if (!startDate || !endDate || startDate > endDate) {
        return context.log(`Invalid report period. start=${reportData.report_start_date} end=${reportData.report_end_date}`);
    }

    const token = context.token;
    const resources = new Resources({ token });
    const services = new Services({ token });
    const recipient = await resolveRecipientEmail(resources, reportData.report_send_to);

    if (!recipient) {
        return context.log(`Invalid report recipient. report_send_to=${reportData.report_send_to}`);
    }

    const targetDevice = await resources.devices.info(reportData.report_device);
    const deviceName = targetDevice.name || reportData.report_device;
    const queryVariables = Array.from(new Set([...reportData.report_variables, "data"]));

    const rawData = await getReportDeviceData(resources, reportData.report_device, queryVariables, startDate, endDate);

    const points: ReportPoint[] = [];

    for (const item of rawData) {
        const time = new Date(item.time || item.created_at || new Date());
        for (const variable of reportData.report_variables) {
            const value = getPointValue(item, variable);
            if (value === null) continue;

            points.push({
                variable,
                label: getVariableLabel(variable),
                value,
                unit: item.unit || variableUnits[variable] || "",
                time
            });
        }
    }

    const summaries = summarize(points, reportData.report_variables);
    const reportParams = {
        data: reportData,
        deviceName,
        startDate,
        endDate,
        points,
        summaries
    };
    let compactPdf = false;
    let html = buildReportHtml(reportParams);
    let htmlSize = Buffer.byteLength(html, "utf8");

    if (htmlSize > PDF_HTML_SAFE_LIMIT_BYTES) {
        compactPdf = true;
        html = buildReportHtml({ ...reportParams, compact: true });
        htmlSize = Buffer.byteLength(html, "utf8");
    }

    context.log(`PDF report HTML size=${htmlSize} bytes compact=${compactPdf}`);

    const safeName = (reportData.report_name || deviceName)
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-zA-Z0-9_-]+/g, "-")
        .replace(/^-|-$/g, "")
        .toLowerCase() || "relatorio";

    const fileName = `relatorio-${safeName}-${formatDate(startDate).replace(/\D/g, "")}-${formatDate(endDate).replace(/\D/g, "")}.pdf`;
    let pdf = await generatePdf(token, html);

    if ((!pdf.status || !pdf.result) && !compactPdf) {
        context.log(`Retrying PDF generation with compact HTML after failure${pdf.error ? `: ${pdf.error}` : ""}`);
        compactPdf = true;
        html = buildReportHtml({ ...reportParams, compact: true });
        htmlSize = Buffer.byteLength(html, "utf8");
        context.log(`PDF compact HTML size=${htmlSize} bytes`);
        pdf = await generatePdf(token, html);
    }

    if (!pdf.status || !pdf.result) {
        return context.log(`Failed to generate PDF report${pdf.error ? `: ${pdf.error}` : ""}`);
    }

    const pdfArchive = normalizePdfArchive(pdf.result);
    if (!pdfArchive) {
        return context.log(`Invalid PDF generated. result_prefix=${String(pdf.result).slice(0, 80)}`);
    }

    try {
        await services.email.send({
            to: recipient.email,
            from: "IrriGate",
            subject: `Relatório IrriGate - ${reportData.report_name || deviceName}`,
            html: `
                <p>Olá${recipient.name ? `, ${escapeHtml(recipient.name)}` : ""},</p>
                <p>Segue em anexo o relatório solicitado para <strong>${escapeHtml(reportData.report_name || deviceName)}</strong>.</p>
                <p><strong>Período:</strong> ${formatDate(startDate)} - ${formatDate(endDate)}</p>
            `,
            attachment: {
                archive: pdfArchive,
                type: "base64",
                filename: fileName
            }
        });
    } catch (error) {
        return context.log(`Error sending report email to ${recipient.email}: ${error}`);
    }

    await resources.devices.sendDeviceData(device_id, {
        variable: "relatorios",
        value: "sent",
        metadata: {
            report_device: reportData.report_device,
            report_device_name: deviceName,
            report_variables: reportData.report_variables,
            report_start_date: startDate.toISOString(),
            report_end_date: endDate.toISOString(),
            report_send_to: recipient.email,
            report_send_to_user: recipient.userId || reportData.report_user,
            report_name: reportData.report_name || deviceName,
            points_count: points.length,
            file_name: fileName,
            created_at: new Date().toISOString()
        }
    });

    const notificationUser = reportData.report_user || recipient.userId;
    if (notificationUser) {
        try {
            await resources.run.notificationCreate(notificationUser, {
                title: "Relatório Enviado",
                message: `O relatório ${reportData.report_name || deviceName} foi enviado para ${recipient.email}.`
            });
        } catch (error) {
            context.log("Error sending report notification:", error);
        }
    }

    context.log(`Report sent successfully to ${recipient.email}`);
}

export { createReport };
export default new Analysis(createReport, { token: "a-f41d9713-49ec-4223-9119-8d71092df091" });
